sql:
SELECT reminder_date 
FROM case_reminders 
WHERE case_id = 1;

SELECT COUNT(*) AS reminder_count
FROM case_reminders
WHERE case_id = 1;

SELECT COUNT(event_id) AS event_count
FROM case_events
WHERE case_id = 1;

SELECT case_id, COUNT(reminder_id) AS reminder_count
FROM case_reminders
GROUP BY case_id;

